using Payments;

namespace PaymentGateway.Tests;

[TestClass]
public sealed class PaymentGatewayChargeTests
{
    private readonly Payments.PaymentGateway _gateway;

    public PaymentGatewayChargeTests()
    {
        _gateway = new Payments.PaymentGateway();
    }

    [TestMethod]
    public async Task ChargeAsync_ValidTokenAndAmount_ReturnsSuccess()
    {
        var result = await _gateway.ChargeAsync("tok_valid_visa", 49.99m);

        Assert.IsNotNull(result);
        Assert.IsTrue(result.Success);
        Assert.IsNotNull(result.ChargeId);
    }

    [TestMethod]
    public async Task ChargeAsync_ValidCharge_ReturnsNonEmptyChargeId()
    {
        var result = await _gateway.ChargeAsync("tok_valid_visa", 100.00m);

        Assert.IsTrue(result.Success);
        Assert.AreNotEqual(string.Empty, result.ChargeId);
    }

    [TestMethod]
    [DataRow(0)]
    [DataRow(-1)]
    [DataRow(-100.50)]
    public async Task ChargeAsync_ZeroOrNegativeAmount_ThrowsArgumentException(double amount)
    {
        await Assert.ThrowsExactlyAsync<ArgumentException>(
            async () => await _gateway.ChargeAsync("tok_valid", (decimal)amount));
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    [DataRow("   ")]
    public async Task ChargeAsync_NullOrEmptyToken_ThrowsArgumentException(string? token)
    {
        await Assert.ThrowsExactlyAsync<ArgumentException>(
            async () => await _gateway.ChargeAsync(token!, 10.00m));
    }

    [TestMethod]
    public async Task ChargeAsync_InvalidToken_ReturnsFailure()
    {
        var result = await _gateway.ChargeAsync("tok_declined", 50.00m);

        Assert.IsNotNull(result);
        Assert.IsFalse(result.Success);
    }

    [TestMethod]
    [DataRow(0.01, DisplayName = "Minimum charge")]
    [DataRow(9999.99, DisplayName = "Large charge")]
    [DataRow(1.00, DisplayName = "One dollar")]
    public async Task ChargeAsync_VariousValidAmounts_ReturnsSuccess(double amount)
    {
        var result = await _gateway.ChargeAsync("tok_valid_visa", (decimal)amount);

        Assert.IsTrue(result.Success);
    }

    [TestMethod]
    public async Task ChargeAsync_MultipleCharges_ReturnUniqueChargeIds()
    {
        var result1 = await _gateway.ChargeAsync("tok_valid_visa", 10.00m);
        var result2 = await _gateway.ChargeAsync("tok_valid_visa", 20.00m);

        Assert.AreNotEqual(result1.ChargeId, result2.ChargeId);
    }
}

[TestClass]
public sealed class PaymentGatewayRefundTests
{
    private readonly Payments.PaymentGateway _gateway;

    public PaymentGatewayRefundTests()
    {
        _gateway = new Payments.PaymentGateway();
    }

    [TestMethod]
    public async Task RefundAsync_ValidChargeId_ReturnsSuccess()
    {
        var result = await _gateway.RefundAsync("ch_valid_123");

        Assert.IsNotNull(result);
        Assert.IsTrue(result.Success);
        Assert.IsNotNull(result.RefundId);
    }

    [TestMethod]
    public async Task RefundAsync_ValidRefund_ReturnsNonEmptyRefundId()
    {
        var result = await _gateway.RefundAsync("ch_valid_123");

        Assert.IsTrue(result.Success);
        Assert.AreNotEqual(string.Empty, result.RefundId);
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    [DataRow("   ")]
    public async Task RefundAsync_NullOrEmptyChargeId_ThrowsArgumentException(string? chargeId)
    {
        await Assert.ThrowsExactlyAsync<ArgumentException>(
            async () => await _gateway.RefundAsync(chargeId!));
    }

    [TestMethod]
    public async Task RefundAsync_NonExistentChargeId_ReturnsFailure()
    {
        var result = await _gateway.RefundAsync("ch_nonexistent_999");

        Assert.IsNotNull(result);
        Assert.IsFalse(result.Success);
    }

    [TestMethod]
    public async Task RefundAsync_AlreadyRefundedCharge_ReturnsFailure()
    {
        // First refund succeeds
        var first = await _gateway.RefundAsync("ch_already_refunded");

        // Second refund on same charge should fail
        var second = await _gateway.RefundAsync("ch_already_refunded");

        Assert.IsFalse(second.Success);
    }
}

