     {
         var result = await _gateway.RefundAsync("ch_valid_123");

         Assert.IsNotNull(result);
         Assert.IsTrue(result.Success);
         Assert.IsNotNull(result.RefundId);
     }

     [TestMethod]
     public async Task RefundAsync_ValidRefund_ReturnsNonEmptyRefundId()
     {
         var result = await _gateway.RefundAsync("ch_valid_123");

         Assert.IsTrue(result.Success);
         Assert.AreNotEqual(string.Empty, result.RefundId);
     }

